    display: flex;
    align-items: center;
    padding: 20px;
    border: 1px solid #ccc;
    border-radius: 8px;
    margin: 20px ;
    background: #f6f7f8;
  }
  
  .shimmer-image {
    width: 200px;
    height: 150px;
    border-radius: 8px;
    background: #e0e0e0;
    position: relative;
    overflow: hidden;
  }
  
  .shimmer-details {
    flex-grow: 1;
    margin: 20px;
  }
  
  .shimmer-line {
    height: 100px;
    width: 50%;
    background: #e0e0e0;
    margin-bottom: 10px;
    position: relative;
    overflow: hidden;
  }
  
  .shimmer-line.short {
    width: 50%;
  }
  
  @keyframes shimmer {
    0% {
      transform: translateX(-100%);
    }
    100% {
      transform: translateX(100%);
    }
  }
  
  .shimmer-image::before,
  .shimmer-line::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    height: 100%;
    width: 100%;
    background: linear-gradient(to right, transparent, rgba(255, 255, 255, 0.5), transparent);
    transform: translateX(-100%);
    animation: shimmer 1.5s infinite;
  }

